-- ============================================
-- Legislacao Bloco 2 misto: Ratinho Junior / Camara Dados Abertos / projetos_lei
-- Promocao completa escopada: autoria principal em tipos verificados
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos v2
--   https://dadosabertos.camara.leg.br/api/v2/deputados/141403
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes?idDeputadoAutor=141403&ordem=DESC&ordenarPor=id&itens=100&pagina=1..11
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509
--   coverage_scope = inventario_completo_camara_autoria_principal_tipos_verificados_2007_2014_cutoff_20260509
--
-- Escopo: 434 proposicoes de autoria principal (ordemAssinatura=1)
-- na Camara, em tipos verificados e anos oficiais positivos, com cutoff em 2026-05-09.
-- 649 rows oficiais ficam formalmente fora do coverage por
-- nao-autoria principal ou ano oficial nao verificavel.
--
-- Esta migration escreve somente em projetos_lei.
-- Esta migration NAO escreve em legislacao_mandato_executivo; valida baseline
-- read-only de 11 rows LME PR que permanecem ampliado_parcial em superficie separada.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  lme_count int;
  lme_target_count int;
  target_divergent_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ratinho-junior';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ratinho-junior: candidato ausente neste banco local/CI minimo; promocao Camara pulada';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl = 0 THEN
    RAISE NOTICE 'ratinho-junior: baseline projetos_lei ausente neste banco local/CI minimo; promocao Camara completo sera no-op';
    RETURN;
  END IF;

  IF total_pl NOT IN (100, 473) THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: esperadas 100 rows antes do insert ou 473 rows idempotentes em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 11 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: baseline LME PR parcial esperado 11, encontrado %', lme_count;
  END IF;

  SELECT count(*) INTO lme_target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509';
  IF lme_target_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: coverage parlamentar novo nao pode existir em LME, encontrado %', lme_target_count;
  END IF;

  SELECT count(*) INTO target_divergent_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('622523', '622522', '622521', '620188', '618269', '616797', '613218', '612245', '564124', '552152', '551802', '551684', '548084', '544199', '540271', '539346', '535581', '535568', '535557', '535547', '535536', '535523', '535518', '530731', '530730', '530729', '530727', '530726', '530725', '530724', '530723', '530722', '530721', '530720', '530719', '530717', '530716', '530715', '530714', '530708', '530707', '530705', '529814', '529813', '529812', '529811', '529810', '529809', '529808', '529807', '529806', '529804', '529802', '529801', '529800', '529799', '529798', '529797', '529796', '526690', '523906', '523295', '523003', '520379', '519818', '519108', '517893', '516112', '515072', '514977', '513768', '513539', '510660', '503990', '503471', '501855', '500848', '500633', '499650', '498145', '495053', '495050', '494625', '493989', '492206', '492205', '491507', '489566', '488871', '488870', '488869', '488868', '487758', '486308', '486306', '485132', '485131', '485129', '484466', '483571', '483570', '480567', '480564', '477229', '476825', '471222', '471221', '470014', '470012', '470011', '470005', '470002', '470001', '470000', '469999', '469998', '469997', '469989', '469988', '469987', '469986', '469985', '469984', '469983', '469981', '469980', '469979', '469268', '469267', '469266', '469265', '469264', '469263', '469262', '469261', '469260', '469259', '469258', '469257', '469256', '469255', '469254', '469253', '469252', '469251', '469250', '467934', '467246', '467245', '467244', '467243', '467242', '467241', '467240', '467237', '467236', '467235', '467233', '467232', '467231', '467230', '467229', '467228', '467227', '467226', '467225', '467224', '467223', '467222', '467221', '467220', '467219', '467218', '467217', '467216', '467215', '467214', '467213', '467212', '467211', '467210', '467209', '467208', '467207', '467116', '467115', '467114', '467113', '467112', '467111', '467110', '467103', '467102', '467099', '467098', '467093', '467092', 