    AND coverage_id IS NOT NULL
    AND coverage_id NOT IN ('ratinho-junior-camara-autoria-principal-ampliado-parcial-lote-a-20260506', 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509');
  IF target_divergent_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ratinho-junior: % rows alvo tem coverage_id divergente', target_divergent_count;
  END IF;
END $$;

CREATE TEMP TABLE _ratinho_junior_camara_completo_should_apply_20260509 ON COMMIT DROP AS
SELECT EXISTS (
  SELECT 1
  FROM candidatos c
  JOIN projetos_lei pl ON pl.candidato_id = c.id
  WHERE c.slug = 'ratinho-junior'
) AS should_apply;

