WITH cand AS (
  SELECT id AS candidato_id
  FROM candidatos
  WHERE slug = 'ratinho-junior'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  url_inteiro_teor,
  fonte,
  proposicao_id_api,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  cand.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.url_inteiro_teor,
  'Camara',
  seed.proposicao_id_api,
  'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509',
  'inventario_completo_camara_autoria_principal_tipos_verificados_2007_2014_cutoff_20260509',
  seed.metadata_patch
FROM cand
CROSS JOIN _ratinho_junior_camara_completo_20260509 seed
WHERE (SELECT should_apply FROM _ratinho_junior_camara_completo_should_apply_20260509)
  AND NOT EXISTS (
  SELECT 1
  FROM projetos_lei pl
  WHERE pl.candidato_id = cand.candidato_id
    AND pl.proposicao_id_api = seed.proposicao_id_api
);

WITH cand AS (
  SELECT id AS candidato_id
  FROM candidatos
  WHERE slug = 'ratinho-junior'
)
UPDATE projetos_lei pl
SET
  coverage_id = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509',
  coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_verificados_2007_2014_cutoff_20260509',
  metadata = COALESCE(pl.metadata, '{}'::jsonb) || seed.metadata_patch
FROM cand
JOIN _ratinho_junior_camara_completo_20260509 seed ON TRUE
WHERE pl.candidato_id = cand.candidato_id
  AND pl.proposicao_id_api = seed.proposicao_id_api
  AND (SELECT should_apply FROM _ratinho_junior_camara_completo_should_apply_20260509)
  AND (pl.coverage_id IS NULL OR pl.coverage_id IN ('ratinho-junior-camara-autoria-principal-ampliado-parcial-lote-a-20260506', 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509'));

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  complete_count int;
  old_partial_count int;
  outside_coverage_count int;
  metadata_ok int;
  lme_count int;
  lme_target_count int;
  other_slugs_with_target int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ratinho-junior';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ratinho-junior: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl = 0 THEN
    RAISE NOTICE 'ratinho-junior: pos-condicao pulada porque baseline projetos_lei nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  IF total_pl <> 473 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: esperado total projetos_lei=473, encontrado %', total_pl;
  END IF;

  SELECT count(*) INTO complete_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509'
    AND coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_verificados_2007_2014_cutoff_20260509';
  IF complete_count <> 434 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: esperadas 434 rows com coverage completo Camara, encontradas %', complete_count;
  END IF;

  SELECT count(*) INTO old_partial_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ratinho-junior-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF old_partial_count <> 6 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: esperadas 6 rows ainda no coverage parcial antigo fora do recorte completo, encontrado %', old_partial_count;
  END IF;

  SELECT count(*) INTO outside_coverage_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id IS DISTINCT FROM 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509';
  IF outside_coverage_count <> 39 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: esperadas 39 rows em projetos_lei fora do recorte completo, encontradas %', outside_coverage_count;
  END IF;

  SELECT count(*) INTO metadata_ok
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509'
    AND coverage_scope = 'inventario_completo_camara_autoria_principal_tipos_verificados_2007_2014_cutoff_20260509'
    AND metadata->>'coverage_id' = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509'
    AND metadata->>'coverage_scope' = 'inventario_completo_camara_autoria_principal_tipos_verificados_2007_2014_cutoff_20260509'
    AND metadata->>'coverage_status' = 'completo_escopado'
    AND metadata->>'tabela_alvo' = 'projetos_lei'
    AND metadata->>'legislacao_mandato_executivo_mixed' = 'false';
  IF metadata_ok <> 434 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: esperadas 434 rows com metadata completo canonico, encontradas %', metadata_ok;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 11 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: LME PR parcial deveria permanecer 11, encontrado %', lme_count;
  END IF;

  SELECT count(*) INTO lme_target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509';
  IF lme_target_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: coverage parlamentar novo nao pode tocar LME, encontrado %', lme_target_count;
  END IF;

  SELECT count(*) INTO other_slugs_with_target
  FROM projetos_lei
  WHERE candidato_id <> cand_id
    AND coverage_id = 'ratinho-junior-camara-completo-autoria-principal-tipos-verificados-2007-2014-cutoff-20260509';
  IF other_slugs_with_target <> 0 THEN
    RAISE EXCEPTION 'Pos-apply ratinho-junior: % rows de outros slugs com coverage_id alvo', other_slugs_with_target;
  END IF;

  RAISE NOTICE 'Pos-apply ratinho-junior Camara completo scoped: projetos_lei=% complete=% fora_recorte=% lme=%',
    total_pl, complete_count, outside_coverage_count, lme_count;
END $$;
